7735	\begin{lemma}[Pushforward sections are sections over the preimage]
7736	  \label{lem:pushforward_obj_obj_mathlib}
7737	  \lean{AlgebraicGeometry.Scheme.Modules.pushforward_obj_obj}
7738	  \mathlibok
7739	  \textit{Provided by Mathlib.}
7740	  For a morphism \(f : X \to Y\), an \(\mathcal{O}_X\)-module \(\mathcal{M}\), and an open
7741	  \(U \subseteq Y\), the sections of the pushforward \(f_*\mathcal{M}\) over \(U\) coincide
7742	  definitionally with the sections of \(\mathcal{M}\) over the preimage:
7743	  \(\Gamma(U, f_*\mathcal{M}) = \Gamma(f^{-1}(U), \mathcal{M})\).
7744	\end{lemma}
